import * as d3 from "d3"
import { useState } from "react"
import ChartDraw from './ChartDraw'

const Chart = (props) => {
	 const [ox, setOx] = useState("Страна");
   const [oy, setOy] = useState([true, false]);
   const [errorMessage, setErrorMessage] = useState("");

	 const handleSubmit = (event) => {
			event.preventDefault();

			const selectedOy = [
				event.target["oy"][0].checked,
				event.target["oy"][1].checked
			];

			if (!selectedOy.some(Boolean)) {
				setErrorMessage("Выберите хотя бы одно значение по оси OY.");
				return;
			}

			setErrorMessage("");
			setOx(event.target["ox"].value);
			setOy(selectedOy);
	 }

	 const createArrGraph = (data, key) => {
        const groupObj = d3.group(data, d => d[key]);
        const arrGraph = [];

        for (const entry of groupObj) {
            const minMax = d3.extent(entry[1].map(d => d["Высота"]));
            arrGraph.push({ labelX: entry[0], values: minMax });
        }

        if (key === "Год") {
            arrGraph.sort((a, b) => Number(a.labelX) - Number(b.labelX));
        }

        return arrGraph;
   }

   return (
    <>
      <h4>Визуализация</h4>
      <form onSubmit={ handleSubmit}>
        <p> Значение по оси OX: </p>
		<div>
          <input type="radio" name="ox" value="Страна" defaultChecked={ ox === "Страна" }/>
		  Страна
		  <br/>		
          <input type="radio" name="ox" value="Год" />
		  Год
		</div>

        <p> Значение по оси OY </p>
		<div>
          <input type="checkbox" name="oy" defaultChecked={ oy[0] === true } />
		  Максимальная высота <br/>
          <input type="checkbox" name="oy" defaultChecked={ oy[1] === true } />
		  Минимальная высота
		</div>

        <p>  
          <button type="submit">Построить </button>
        </p>
      </form>
			{errorMessage ? <p style={{ color: "red" }}>{errorMessage}</p> : null}
			{!errorMessage ? (
				<ChartDraw data={ createArrGraph(props.data, ox) } oy={ oy } />
			) : null}
	</>
    )
}

export default Chart;
